import React, { useEffect, useRef } from "react";
import Lottie from "lottie-web";
import animate from "lottie-web";
import { FRONT_PAGE_DESC, FRONT_PAGE_NAME } from "../root.link";


const About = () => {
  const container = useRef(null);

  useEffect(() => {
    Lottie.loadAnimation({
      container: container.current,
      renderer: "svg",
      loop: true,
      autoplay: true,
      animationData: require("./astronaout.json"),
    });
    animate.setSpeed(0.5);
  }, []);

  return (
    <section
      id="about"
      className="about section my-16 px-5 md:my-32 flex flex-col flex-wrap space-y-16 md:space-y-0 patterns"
    >
      <div className="ml-auto w-72 md:w-96 lg:w-2/5">
        <div className="container" ref={container}></div>
      </div>
      <header className="text-2xl font-bold pt-10">
        <h2>About</h2>
      </header>
      <div className="max-w-md mb-auto space-y-5">
        <h2 id="user-detail-name" className=" text-5xl font-bold md:text-7xl">
          Hello. I’m Ojas Bendale
        </h2>
        <img
          src="./images/profileImg.jpg"
          className="home-img rounded-full profile__img"
          alt="profilrImg"
        />
        <p id="user-detail-intro" className="tracking-wide leading-relaxed">
          {FRONT_PAGE_DESC}{" "}
        </p>

        <a
          id="resume-button-2"
          href="./Ojas_Bendale_Resume.pdf"
          rel="noreferrer"
          onClick={() =>
            window.open(
              "https://drive.google.com/file/d/17pL_qb8DTmZvNZb5xhAd63DGuAObwPZo/view?usp=share_link"
            )
          }
          className="nav-link resume py-1"
          download="Ojas_Bendale_Resume"
        >
          <button className="px-4 py-2 rounded-md bg-yellow-200 text-black mt-2">
            Resume
          </button>
        </a>
      </div>
    </section>
  );
};

export default About;
